    <script>
        // --- Hiệu ứng hạt ---
        const canvas = document.getElementById('particle-canvas');
        const ctx = canvas.getContext('2d');
        canvas.width = window.innerWidth;
        canvas.height = window.innerHeight;

        let particles = [];
        const particleCount = 100;

        class Particle {
            constructor() {
                this.x = Math.random() * canvas.width;
                this.y = Math.random() * canvas.height;
                this.size = Math.random() * 2 + 1;
                this.speedX = (Math.random() * 2 - 1) * 0.5;
                this.speedY = (Math.random() * 2 - 1) * 0.5;
                this.color = Math.random() > 0.5 ? 'rgba(255, 69, 106, 0.8)' : 'rgba(159, 77, 255, 0.8)';
            }
            update() {
                this.x += this.speedX;
                this.y += this.speedY;
                if (this.x > canvas.width || this.x < 0) this.speedX *= -1;
                if (this.y > canvas.height || this.y < 0) this.speedY *= -1;
            }
            draw() {
                ctx.fillStyle = this.color;
                ctx.beginPath();
                ctx.arc(this.x, this.y, this.size, 0, Math.PI * 2);
                ctx.fill();
            }
        }

        function initParticles() {
            for (let i = 0; i < particleCount; i++) {
                particles.push(new Particle());
            }
        }

        function animateParticles() {
            ctx.clearRect(0, 0, canvas.width, canvas.height);
            for (let i = 0; i < particles.length; i++) {
                particles[i].update();
                particles[i].draw();
            }
            requestAnimationFrame(animateParticles);
        }

        initParticles();
        animateParticles();
        window.addEventListener('resize', () => {
            canvas.width = window.innerWidth;
            canvas.height = window.innerHeight;
            particles = [];
            initParticles();
        });

        // --- Chuyển đổi tab ---
        const tabs = document.querySelectorAll('.tab-btn');
        const panes = document.querySelectorAll('.tab-pane');

        tabs.forEach(tab => {
            tab.addEventListener('click', () => {
                tabs.forEach(t => t.classList.remove('active'));
                panes.forEach(p => p.classList.remove('active'));

                tab.classList.add('active');
                document.getElementById(tab.dataset.tab).classList.add('active');

                showFeedback(`Đã chuyển sang: ${tab.textContent}`);
            });
        });

        // --- Gửi biểu mẫu ---
        document.getElementById('user-profile-form').addEventListener('submit', function(event) {
            event.preventDefault();
            const userProfile = {
                name: document.getElementById('user-name').value,
                age: document.getElementById('user-age').value,
                gender: document.getElementById('user-gender').value,
                background: document.getElementById('user-background').value
            };
            const profileJson = JSON.stringify(userProfile, null, 2);

            // -- QUAN TRỌNG: Vui lòng thay thế thông tin sách thế giới của bạn tại đây --
            const wiFilename = "对魔忍 新世界20251027230811082_Worldbooks";
            const wiUid = "22";

            const command = `/setentryfield file="${wiFilename}" uid=${wiUid} field=content ${profileJson}`;

            if (typeof triggerSlash === 'function') {
                triggerSlash(command);
                showFeedback("Hồ sơ đã được đồng bộ vào cơ sở dữ liệu...");
            } else {
                console.warn("triggerSlash not available. Command:", command);
                showFeedback("Chế độ gỡ lỗi: Lệnh đã được in ra bảng điều khiển.");
            }
        });

        // --- Chuyển đổi mở đầu ---
        async function switchToOpening(swipeId) {
            showFeedback(`Đang tải cốt truyện ${swipeId}...`);
             // Vô hiệu hóa nút khi nhấp để tránh nhấp lặp lại
            const card = event.currentTarget;
            if (card) {
                 card.style.opacity = '0.6';
                 card.style.pointerEvents = 'none';
            }
            try {
                if(typeof setChatMessage !== 'function') throw new Error("API not available");

                const messages = await getChatMessages("0", { include_swipe: true });
                if (messages && messages[0].swipes && messages[0].swipes[swipeId]) {
                    await setChatMessage(messages[0].swipes[swipeId], 0, {
                        swipe_id: swipeId,
                        refresh: 'display_and_render_current'
                    });
                } else {
                     throw new Error(`Không tìm thấy cốt truyện ${swipeId}. Vui lòng kiểm tra cấu hình thẻ nhân vật.`);
                }
            } catch (error) {
                console.error('Chuyển đổi mở đầu thất bại:', error);
                showFeedback(`Lỗi: ${error.message}`);
                // Nếu thất bại, khôi phục trạng thái nút
                if(card){
                    card.style.opacity = '1';
                    card.style.pointerEvents = 'auto';
                }
            }
        }

        // --- Bong bóng phản hồi tương tác ---
        let feedbackTimeout;
        function showFeedback(message) {
            const bubble = document.getElementById('feedback-bubble');
            bubble.textContent = message;
            bubble.classList.add('show');

            clearTimeout(feedbackTimeout);
            feedbackTimeout = setTimeout(() => {
                bubble.classList.remove('show');
            }, 3000);
        }

