                      if (!blob) {
                        alert('Xử lý hình ảnh thất bại, không thể tạo đối tượng Blob.');
                        uploadInput.value = '';
                        return;
                      }

                      if (blob.size > 800 * 1024) {
                        alert('Hình ảnh sau khi nén vẫn còn quá lớn. Vui lòng chọn hình ảnh nhỏ hơn.');
                        uploadInput.value = '';
                        return;
                      }

                      try {
                        await idbHelper.set(storageKey, blob);
                        await updatePortrait(jsonData);
                        resetTrigger.style.display = 'flex';
                        console.log(`Avatar đã được lưu, kích thước sau nén khoảng ${Math.round(blob.size / 1024)}KB`);
                      } catch (error) {
                        console.error('Lưu avatar vào IndexedDB thất bại:', error);
                        if (error.name === 'QuotaExceededError') {
                          alert(
                            'Không gian lưu trữ trình duyệt không đủ. IndexedDB đã đầy.\nVui lòng dọn dẹp dữ liệu trình duyệt hoặc sử dụng hình ảnh nhỏ hơn.',
                          );
                        } else {
                          alert(`Lưu avatar thất bại: ${error.message}`);
                        }
                      } finally {
                        uploadInput.value = '';
                      }
                    },
                    'image/jpeg',
                    0.7,
                  );
                };
                img.onerror = () => {
                  alert('Không thể tải tệp đã chọn, có thể không phải là định dạng hình ảnh hợp lệ.');
                  uploadInput.value = '';
                };
                img.src = e.target.result;
              };
              reader.onerror = () => {
                alert('Đọc tệp thất bại.');
                uploadInput.value = '';
